mapper.select:
SELECT o.id, o.order_no AS orderNo, o.user_id AS userId, o.total_amount AS totalAmount, o.pay_amount AS payAmount, o.status, o.pay_type AS payType, o.pay_time AS payTime, o.receiver_name AS receiverName, o.receiver_phone AS receiverPhone, o.receiver_address AS receiverAddress, o.remark, o.created_at AS createdAt, o.updated_at AS updatedAt, u.username, u.real_name AS realName FROM orders o LEFT JOIN user u ON o.user_id = u.id WHERE 1=1
AND o.order_no LIKE CONCAT('%', #{orderNo}, '%')
AND o.status = #{status}
AND DATE(o.created_at) >= #{startDate}
AND DATE(o.created_at) <= #{endDate}
ORDER BY o.created_at DESC

SELECT DATE(created_at) AS `date`, COUNT(id) AS `orders`, IFNULL(SUM(pay_amount), 0) AS `sales` FROM orders WHERE status IN (1, 2, 3)
AND created_at >= DATE_SUB(CURDATE(), INTERVAL #{days} DAY)
AND DATE(created_at) >= #{startDate}
AND DATE(created_at) <= #{endDate}
GROUP BY DATE(created_at) ORDER BY DATE(created_at) ASC
